import (
	context "context"
	fern "github.com/openapi-request-body-ref/fern"
	fernclient "github.com/openapi-request-body-ref/fern/client"
)

client := fernclient.NewClient()
response, err := client.Catalog.CreateCatalogImage(
	context.TODO(),
	&fern.CreateCatalogImageBody{
		Request: &fern.CreateCatalogImageRequest{
			CatalogObjectID: "catalog_object_id",
		},
	},
)

